  1	import { useResolvedExtensions } from '@openshift-console/dynamic-plugin-sdk';
  2	import { act, fireEvent, render, waitFor } from '@testing-library/react';
  3	import * as React from 'react';
  4	import { AlertsResult, SilencedAlert } from '../../api/alert';
  5	import { FlowMetricsResult, GenericMetricsResult } from '../../api/loki';
  6	import { getConfig, getFlowGenericMetrics, getFlowMetrics, getFlowRecords, getRole } from '../../api/routes';
  7	import { FlowQuery } from '../../model/flow-query';
  8	import { FullConfigResultSample, SimpleConfigResultSample } from '../__tests-data__/config';
  9	import { extensionsMock } from '../__tests-data__/extensions';
 10	import { FlowsResultSample } from '../__tests-data__/flows';
 11	import NetflowTraffic from '../netflow-traffic';
 12	import NetflowTrafficParent from '../netflow-traffic-parent';
 13	
 14	const useResolvedExtensionsMock = useResolvedExtensions as jest.Mock;
 15	
 16	jest.mock('../../api/routes', () => ({
 17	  getConfig: jest.fn(() => Promise.resolve(FullConfigResultSample)),
 18	  getRole: jest.fn(() => Promise.resolve('admin')),
 19	  getFlowRecords: jest.fn(() => Promise.resolve(FlowsResultSample)),
 20	  getFlowMetrics: jest.fn(() =>
 21	    Promise.resolve({
 22	      metrics: [],
 23	      stats: { numQueries: 0, limitReached: false, dataSources: ['loki'] }
 24	    } as FlowMetricsResult)
 25	  ),
 26	  getFlowGenericMetrics: jest.fn(() =>
 27	    Promise.resolve({
 28	      metrics: [],
 29	      stats: { numQueries: 0, limitReached: false, dataSources: ['loki'] }
 30	    } as GenericMetricsResult)
 31	  ),
 32	  getAlerts: jest.fn(() => Promise.resolve({ data: { groups: [] }, status: 'success' } as AlertsResult)),
 33	  getSilencedAlerts: jest.fn(() => Promise.resolve([] as SilencedAlert[]))
 34	}));
 35	
 36	const getConfigMock = getConfig as jest.Mock;
 37	const getRoleMock = getRole as jest.Mock;
 38	const getFlowsMock = getFlowRecords as jest.Mock;
 39	const getMetricsMock = getFlowMetrics as jest.Mock;
 40	const getGenericMetricsMock = getFlowGenericMetrics as jest.Mock;
 41	
 42	const defaultQuery = {
 43	  aggregateBy: 'namespace',
 44	  filters: '',
 45	  groups: undefined,
 46	  limit: 5,
 47	  packetLoss: 'all',
 48	  rateInterval: '30s',
 49	  recordType: 'flowLog',
 50	  dataSource: 'auto',
 51	  step: '15s',
 52	  timeRange: 300
 53	} as FlowQuery;
 54	
 55	describe('<NetflowTraffic />', () => {
 56	  beforeAll(() => {
 57	    useResolvedExtensionsMock.mockReturnValue(extensionsMock);
 58	  });
 59	
 60	  afterEach(() => {
 61	    jest.clearAllMocks();
 62	  });
 63	
 64	  it('should render component', async () => {
 65	    const { container } = render(<NetflowTrafficParent />);
 66	    await act(async () => {
 67	      await new Promise(r => setTimeout(r, 0));
 68	    });
 69	    expect(container.firstChild).toBeTruthy();
 70	  });
 71	
 72	  it('should render refresh components', async () => {
 73	    const { container } = render(<NetflowTraffic />);
 74	    await act(async () => {
 75	      await new Promise(r => setTimeout(r, 0));
 76	    });
 77	    expect(container.querySelector('#refresh-dropdown-container')).toBeTruthy();
 78	    expect(container.querySelector('#refresh-button')).toBeTruthy();
 79	  });
 80	
 81	  it('should load default metrics on button click', async () => {
 82	    const { container } = render(<NetflowTrafficParent />);
 83	    const expectedMetricsQueries: FlowQuery[] = [
 84	      { ...defaultQuery, function: 'rate', type: 'Bytes' },
 85	      { ...defaultQuery, function: 'rate', type: 'Packets' },
 86	      { ...defaultQuery, function: 'rate', aggregateBy: 'app', type: 'Bytes' },
 87	      { ...defaultQuery, function: 'rate', aggregateBy: 'app', type: 'Packets' },
 88	      { ...defaultQuery, function: 'rate', type: 'PktDropPackets' },
 89	      { ...defaultQuery, function: 'rate', aggregateBy: 'app', type: 'PktDropPackets' },
 90	      { ...defaultQuery, function: 'avg', type: 'DnsLatencyMs' },
 91	      { ...defaultQuery, function: 'p90', type: 'DnsLatencyMs' },
 92	      { ...defaultQuery, function: 'avg', aggregateBy: 'app', type: 'DnsLatencyMs' },
 93	      { ...defaultQuery, function: 'p90', aggregateBy: 'app', type: 'DnsLatencyMs' },
 94	      { ...defaultQuery, function: 'avg', type: 'TimeFlowRttNs' },
 95	      { ...defaultQuery, function: 'min', type: 'TimeFlowRttNs' },
 96	      { ...defaultQuery, function: 'p90', type: 'TimeFlowRttNs' },
 97	      { ...defaultQuery, function: 'avg', aggregateBy: 'app', type: 'TimeFlowRttNs' },
 98	      { ...defaultQuery, function: 'min', aggregateBy: 'app', type: 'TimeFlowRttNs' },
 99	      { ...defaultQuery, function: 'p90', aggregateBy: 'app', type: 'TimeFlowRttNs' }
100	    ];
101	    const expectedGenericMetricsQueries: FlowQuery[] = [
102	      { ...defaultQuery, function: 'rate', type: 'PktDropPackets', aggregateBy: 'PktDropLatestState' },
103	      { ...defaultQuery, function: 'rate', type: 'PktDropPackets', aggregateBy: 'PktDropLatestDropCause' },
104	      { ...defaultQuery, function: 'count', type: 'DnsFlows', aggregateBy: 'DnsName' },
105	      { ...defaultQuery, function: 'count', type: 'DnsFlows', aggregateBy: 'DnsFlagsResponseCode' },
106	      { ...defaultQuery, function: 'count', type: 'DnsFlows', aggregateBy: 'app' }
107	    ];
108	
109	    await waitFor(() => {
110	      expect(getConfigMock).toHaveBeenCalledTimes(1);
111	      expect(getRoleMock).toHaveBeenCalledTimes(1);
112	      expect(getFlowsMock).toHaveBeenCalledTimes(0);
113	      expect(getMetricsMock).toHaveBeenCalledTimes(expectedMetricsQueries.length);
114	      expectedMetricsQueries.forEach((q, i) =>
115	        expect(getMetricsMock).toHaveBeenNthCalledWith(i + 1, q, defaultQuery.timeRange)
116	      );
117	      expect(getGenericMetricsMock).toHaveBeenCalledTimes(expectedGenericMetricsQueries.length);
118	    });
119	
120	    await act(async () => {
121	      fireEvent.click(container.querySelector('#refresh-button')!);
122	    });
123	
124	    await waitFor(() => {
125	      expect(getConfigMock).toHaveBeenCalledTimes(1);
126	      expect(getRoleMock).toHaveBeenCalledTimes(1);
127	      expect(getFlowsMock).toHaveBeenCalledTimes(0);
128	      expect(getMetricsMock).toHaveBeenCalledTimes(expectedMetricsQueries.length * 2);
129	      expect(getGenericMetricsMock).toHaveBeenCalledTimes(expectedGenericMetricsQueries.length * 2);
130	    });
131	  });
132	
133	  it('should render toolbar components when config loaded', async () => {
134	    const { container } = render(<NetflowTrafficParent />);
135	    await waitFor(() => {
136	      expect(getConfigMock).toHaveBeenCalled();
137	      expect(getRoleMock).toHaveBeenCalled();
138	    });
139	    await waitFor(() => {
140	      expect(container.querySelector('#filter-toolbar')).toBeTruthy();
141	    });
142	  });
143	
144	  it('should load basic metrics on button click', async () => {
145	    getConfigMock.mockReturnValue(Promise.resolve(SimpleConfigResultSample));
146	
147	    const { container } = render(<NetflowTrafficParent />);
148	    await waitFor(() => {
149	      expect(getConfigMock).toHaveBeenCalledTimes(1);
150	      expect(getRoleMock).toHaveBeenCalledTimes(1);
151	      expect(getFlowsMock).toHaveBeenCalledTimes(0);
152	      expect(getMetricsMock).toHaveBeenCalledTimes(2);
153	      expect(getGenericMetricsMock).toHaveBeenCalledTimes(0);
154	    });
155	
156	    await act(async () => {
157	      fireEvent.click(container.querySelector('#refresh-button')!);
158	    });
159	
160	    await waitFor(() => {
161	      expect(getConfigMock).toHaveBeenCalledTimes(1);
162	      expect(getRoleMock).toHaveBeenCalledTimes(1);
163	      expect(getFlowsMock).toHaveBeenCalledTimes(0);
164	      expect(getMetricsMock).toHaveBeenCalledTimes(4);
165	      expect(getGenericMetricsMock).toHaveBeenCalledTimes(0);
166	    });
167	  });
168	});

